// Calculate daily stats
const orders = $input.all();

const totalRevenue = orders.reduce((sum, o) => sum + parseFloat(o.json.total || 0), 0);
const orderCount = orders.length;
const avgOrder = orderCount > 0 ? totalRevenue / orderCount : 0;

// Count flavors
const flavorCount = {};
orders.forEach(o => {
  const item = o.json.line_items?.[0]?.name || 'Unknown';
  flavorCount[item] = (flavorCount[item] || 0) + 1;
});

// Top 5 flavors
const topFlavors = Object.entries(flavorCount)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([flavor, count]) => `${flavor}: ${count}`);

// Unique customers
const uniqueCustomers = [...new Set(orders.map(o => o.json.customer?.email))].length;

return [{
  json: {
    totalRevenue: totalRevenue.toFixed(2),
    orderCount,
    avgOrder: avgOrder.toFixed(2),
    uniqueCustomers,
    topFlavors: topFlavors.join('\n'),
    topFlavor: topFlavors[0] || 'N/A'
  }
}];

